use actix_files::Files;
use actix_web::{web, App, HttpServer, Responder};
use std::path::PathBuf;

async fn serve_file(path: web::Path<String>) -> impl Responder {
    let uploads_dir = PathBuf::from("uploads");
    let file_path = uploads_dir.join(&path);

    if file_path.starts_with(&uploads_dir) && file_path.is_file() {
        Files::new(file_path)
    } else {
        HttpResponse::NotFound().body("File not found")
    }
}

#[actix_web::main]
async fn main() -> std::io::Result<()> {
    HttpServer::new(|| {
        App::new()
            .service(web::resource("/{filename:.*}").route(web::get().to(serve_file)))
    })
    .bind("127.0.0.1:8080")?
    .run()
    .await
}